.starhorse-menu {
  margin: 0;
  padding: 0;
  height: 100%;
  width: 100%;
  clear: both;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  background: var(--star-horse-style);

  .menu-base {
    flex: 1;
    display: flex;
    flex-direction: column;

    .menu-item {
      width: 100%;
      height: 80px;
      flex-direction: column;
      display: inline-flex;
      justify-content: center;
      align-items: center;
      vertical-align: middle;
      cursor: pointer;

      .menu-item-icon {
        width: 100%;
        height: 45px;

        .star-icon {

          width: 100%;
          height: inherit;

          svg {
            color: var(--star-horse-white) !important;
            height: 2em;
            width: 2em;
          }

        }
      }

      .menu-item-title {
        line-height: 30px;
        width: 100%;
        display: inline-flex;
        justify-content: center;
        align-items: center;
        font-weight: bold;
        font-size: 13px;
        color: var(--star-horse-white);
      }

      .menu-item-line {
        height: 2px;
        width: 90%;
        border-bottom: 1px solid var(--star-horse-disable);
      }

      .menu-sub-item {
        display: none;
        opacity: 0;
        position: fixed;
        top: v-bind(top);
        left: 90px;
        transition-delay: 1s;
        flex-direction: column;
        align-items: center;
        vertical-align: middle;
        z-index: 9992 !important;
        background: #f9f9f9;
        border: var(--star-horse-white);
        height: calc(100vh - v-bind(htop));
        width: 200px;
      }
    }

    .is-active:hover:after {
      display: block;
    }

    .is-active {
      position: relative;

      &:hover .menu-sub-item {
        display: flex;
        opacity: 1;
      }
    }

    .is-active:after {
      display: none;
      position: absolute;
      content: '';
      top: 40%;
      right: 0;
      border-right: 10px solid #f9f9f9;
      border-bottom: 10px solid transparent;
      border-top: 10px solid transparent;
      z-index: 9991;
      width: 0;
      height: 0;
    }
  }
}

